import { h } from '@stencil/core';
import { InitialCardProps,  } from '../types';

export const InitialCard = ({ handleProceedQuiz, quizTitle, quizDescription, isLoading, btnTitle }: InitialCardProps) => {
  return (
    <div class="parent-container initial-side-card d-flex">
      <div class="d-flex flex-row justify-content-start gap-3" aria-labelledby="initial-label">
        <div class="parent-container-child initial-side-card">
          <div class="parent-container__content">
          <h2 class="parent-container_child__header mb-0">{quizTitle}</h2>
            <p class="parent-container_child__paragraph">{quizDescription}</p>
          </div>
          <div class="parent-container_child__button">
              <button-component label="Take the quiz" isLoading={isLoading} onBtnClick={() => handleProceedQuiz()} btnId = "initial-quiz-start">
                {btnTitle}
              </button-component>
            </div>
        </div>
        <div class="parent-container__right___column"></div>
      </div>
    </div>
  );
};