import { h } from '@stencil/core';
import { ResultCardProps } from '../beacon-types';

export const ResultCard = ({ pyBtnTitle, syBtnTitle, result, handleRevealAllAnswers, handleRestartQuiz, customText, syBtnUrl }: ResultCardProps) => {
    return (
        <div class="parent-container initial-side-card d-flex final-card">
            <div class="d-flex flex-row justify-content-start gap-3" aria-labelledby="initial-label">
                <div class="parent-container-child">
                    <div class="parent-container__content">
                        <h2 class="parent-container_child__header">{result}</h2>
                        {/* button1 */}
                        <button-component
                            label={pyBtnTitle}
                            onBtnClick={handleRestartQuiz || (() => {})}
                            btnId="take-quiz-again"
                        >
                            {pyBtnTitle}
                        </button-component>
                        <p class="parent-container_child__paragraph">
                            {customText}
                        </p>
                    </div>
                    <div class="parent-container_child__button">
                        <div class="osa-toast mt-2">
                            {/* Buttton 2 */}
                            <button-component 
                                label={syBtnTitle} 
                                onBtnClick={syBtnUrl ? () => window.location.href = syBtnUrl : handleRevealAllAnswers} 
                                isbtnprimary="No" 
                                isArrow={false} 
                                btnId="find-trial"
                            >
                                {syBtnTitle}
                            </button-component>
                        </div>
                    </div>
                </div>
                <div class="parent-container__right___column"></div>
            </div>
        </div>
    );
};
