import { h } from '@stencil/core';
import { isCorrectAns } from '../helpers';
import { QnACardProps } from '../types';
import { BackIcon, GreenCheckIcon, RedCrossIcon } from '../svg/Svg';

// Helper function to get the correct answer text
const getCorrectAnswerText = (structure) => {
  if (structure.correct_answer && structure[structure.correct_answer]) {
    return String(structure[structure.correct_answer]).toLowerCase();
  }
  return '';
};

const renderFeedback = ({ isClicked, capturedAnswer, isAnswerRevealed, structure, handleRevealAnswer }) => {
  // Don't show feedback for questions without correct_answer (like demographic questions)
  if (!structure.correct_answer) {
    return null;
  }
  
  const correctAnswerText = getCorrectAnswerText(structure);
  return (
    <>
      {isClicked && capturedAnswer && isAnswerRevealed.timeodOutReveal && (
        <div class="feedback-wrapper">
          <div class="feedback-message">
            <span class="feedback-icon">
              <GreenCheckIcon className="feedback-icon__img" strokeColor={"#025676"} />
            </span>
            <span class="feedback-wrapper__text d-flex align-items-center" role="alert">
              <span>
                The correct answer is{correctAnswerText ? ` ${correctAnswerText.charAt(0).toLowerCase() + correctAnswerText.slice(1)}` : ''}
              </span>
            </span>
          </div>
        </div>
      )}
      {!capturedAnswer && isClicked && (
        <div class="feedback-wrapper">
          <div class="feedback-message">
            <span class="feedback-icon">
              <span class="d-flex align-items-center">
                <RedCrossIcon className="feedback-icon__img" strokeColor={"#CE1562"}/>
              </span>
            </span>
            <span class="feedback-wrapper__text d-flex align-items-center font-bold small" role="alert">
              {isAnswerRevealed.moreThanOneWrongAttempt ? (
                <span>
                  Try again or&nbsp;
                  <button
                    type="button"
                    aria-label="see the correct answer"
                    class="nonRoutingLink btn p-0 text-decoration-underline fc-neutral-black c-fs-16 c-fw-400 c-lh-125"
                    onClick={() => handleRevealAnswer()}
                  >
                    <span class="d-flex feedback-wrapper__text answer">see the correct answer</span>
                  </button>
                </span>
              ) : (
                <span>
                  Try again or&nbsp;
                  <button
                    type="button"
                    aria-label="see the answer"
                    class="nonRoutingLink btn p-0 text-decoration-underline fc-neutral-black c-fs-16 c-fw-400 c-lh-125"
                    onClick={() => handleRevealAnswer()}
                  >
                    <span class="d-flex feedback-wrapper__text answer">see the answer</span>
                  </button>
                </span>
              )}
            </span>
          </div>
        </div>
      )}
      {isClicked && capturedAnswer && isAnswerRevealed.timeodOutReveal && <p class="explanation-text">{structure?.explanation}</p>}
    </>
  );
};

const renderHighlightedWord = (question: string, word: string) =>{
  const parts = question.split(new RegExp(`\\b${word}\\b`, 'g'));
  const matches = question.match(new RegExp(`\\b${word}\\b`, 'g')) || [];
  return (
    <span>
      {parts.map((part, idx) => (
        <span key={idx}>
          {part}
          {idx < matches.length && (
            <strong>{word}</strong>
          )}
        </span>
      ))}
    </span>
  );
}

export const QnACard = ({
  structure,
  clickHandle,
  isClicked,
  capturedAnswer,
  handleRevealAnswer,
  capturedIndex,
  handleProceedToNextQuestion,
  isAnswerRevealed,
  status,
  handleProceedQuiz,
  isMobile,
  isLastQuestion = false,
}: QnACardProps & { isLastQuestion?: boolean }) => {
  const optionRefs = [];
  const optionEntries = Object.entries(structure).filter(([key]) => key.startsWith('option'));
  //  keyboard navigation
  const focusOption = (idx: number) => {
    optionRefs[idx] && optionRefs[idx].focus && optionRefs[idx].focus();
  };

  const handleKeyDown = (e: KeyboardEvent, idx: number) => {
    const total = optionEntries.length;

    if (e.key === 'ArrowDown' || e.key === 'ArrowRight') {
      e.preventDefault();
      focusOption((idx + 1) % total);
      return;
    }

    if (e.key === 'ArrowUp' || e.key === 'ArrowLeft') {
      e.preventDefault();
      focusOption((idx - 1 + total) % total);
      return;
    }

    if (e.key === ' ' || e.key === 'Enter') {
      e.preventDefault();
      const [key, value] = optionEntries[idx];
      const isCorrect = structure.correct_answer ? isCorrectAns(key, structure.correct_answer) : true; // For questions without correct_answer (like demographics), treat all as correct
      clickHandle({ text: value, isCorrect }, idx);
    }
  };

  // Mobile feedback logic - don't show feedback for questions without correct_answer (like demographics)
  const correctAnswerText = getCorrectAnswerText(structure);
  const isCorrectMobile = isMobile && isClicked && capturedAnswer && isAnswerRevealed.timeodOutReveal && structure.correct_answer;
  const isIncorrectMobile = isMobile && !capturedAnswer && isClicked && structure.correct_answer;

  
  return (
    <div class="quiz-container">
      <div class="stats-wrapper">{status}</div>
      <div class="quiz-container__content">
        <div class="content-wrapper">
          <div class="left-column">
            <legend id="question-label" class={`mb-0 ${!isMobile && "pb-1"} ${structure?.sub_header ? 'mt-0' : ""}`}>
              <strong class="question_label__sub_header">{structure.sub_header}</strong>
              <br />
              {structure?.requiresHighlight
                ? renderHighlightedWord(structure?.question, structure?.highlight || '')
                : structure?.question} 
            </legend>
            {/* Feedback/explanation for desktop */}
            <div class="feedback-desktop">
              {renderFeedback({
                isClicked,
                capturedAnswer,
                isAnswerRevealed,
                structure,
                handleRevealAnswer,
              })}
            </div>
          </div>
          <div class="right-column">
            <form class="question-form" aria-labelledby="question-label">
              <fieldset>
                <div class="options-wrapper">
                  {/* Mobile: show correct feedback above options if correct, otherwise nothing */}
                  {isCorrectMobile && (
                    <div class="feedback-mobile">
                      <div class="feedback-wrapper">
                        <div class="feedback-message">
                          <span class="feedback-icon">
                            {/* correct */}
                            <GreenCheckIcon className="feedback-icon__img" strokeColor={"#025676"}/>
                          </span>
                          <span class="feedback-wrapper__text d-flex align-items-center" role="alert">
                            <span>
                              The correct answer is{correctAnswerText ? ` ${correctAnswerText.charAt(0).toLowerCase() + correctAnswerText.slice(1)}` : ''}
                            </span>
                          </span>
                        </div>
                      </div>
                    </div>
                  )}
                  {optionEntries.map(([key, value], index) => {
                    const isCorrect = structure.correct_answer ? isCorrectAns(key, structure.correct_answer) : true; // For questions without correct_answer, treat all as correct
                    const checked = capturedIndex === index;
                    
                    // For questions without correct_answer (demographic), only style the selected option
                    const isDemographicQuestion = !structure.correct_answer;
                    
                    return (
                      <label
                        class={`option-label option_quiz-${
                          isAnswerRevealed.timeodOutReveal
                            ? isDemographicQuestion
                              ? checked ? 'correct clicked' : '' // For demographic questions, only style the selected option
                              : isCorrect
                              ? 'correct clicked'
                              : isMobile ? 'dp' : ''
                            : checked && isCorrect
                            ? isClicked
                              ? 'correct clicked'
                              : ''
                            : checked && !isCorrect && isClicked
                            ? 'incorrect clicked'
                            : ''
                        }`}
                        tabIndex={0}
                        aria-label={value}
                        ref={el => (optionRefs[index] = el)}
                        onKeyDown={e => {
                          if (!isAnswerRevealed.timeodOutReveal || isDemographicQuestion) handleKeyDown(e, index);
                        }}
                        id={`quiz-option-${index + 1}`}
                        onClick={() => {
                          if (!isAnswerRevealed.timeodOutReveal || isDemographicQuestion) {
                            const isCorrectForLastQuestion = structure.correct_answer ? isCorrectAns(key, structure.correct_answer) : true;
                            clickHandle({ text: value, isCorrect: isCorrectForLastQuestion, totalOptions: optionEntries.length }, index);
                          }
                        }}
                        key={key}
                        style={isAnswerRevealed.timeodOutReveal && !isDemographicQuestion ? {pointerEvents: 'none'} : {}}
                      >
                        <span class="label-span">{value}</span>
                      </label>
                    );
                  })}
                  {/* Mobile: show explanation after options if correct */}
                  {isCorrectMobile && <p class="explanation-text">{structure?.explanation}</p>}
                  {/* Desktop: do NOT render explanation here, keep it in renderFeedback */}
                </div>
              </fieldset>
            </form>
            {/* Mobile: show incorrect feedback below options as before */}
            {isIncorrectMobile && (
              <div class="feedback-mobile incorrect">
                <div class="feedback-wrapper">
                  <div class="feedback-message">
                    <span class="feedback-icon">
                      <span class="d-flex align-items-center">
                        <RedCrossIcon className="feedback-icon__img" strokeColor={"#CE1562"}/>
                      </span>
                    </span>
                    <span class="feedback-wrapper__text d-flex align-items-center font-bold small" role="alert">
                      {isAnswerRevealed.moreThanOneWrongAttempt ? (
                        <span>
                          Try again or&nbsp;
                          <button
                            type="button"
                            aria-label="see the correct answer"
                            class="nonRoutingLink btn p-0 text-decoration-underline fc-neutral-black c-fs-16 c-fw-400 c-lh-125"
                            onClick={() => handleRevealAnswer()}
                          >
                            <span class="d-flex feedback-wrapper__text answer">see the correct answer</span>
                          </button>
                        </span>
                      ) : (
                        <span>
                          Try again or&nbsp;
                          <button
                            type="button"
                            aria-label="see the answer"
                            class="nonRoutingLink btn p-0 text-decoration-underline fc-neutral-black c-fs-16 c-fw-400 c-lh-125"
                            onClick={() => handleRevealAnswer()}
                          >
                            <span class="d-flex feedback-wrapper__text answer">see the answer</span>
                          </button>
                        </span>
                      )}
                    </span>
                  </div>
                </div>
              </div>
            )}
            {/* Desktop: keep feedback as before */}
            <div class="feedback-mobile" style={{ display: 'none' }}></div>
          </div>
        </div>
        <div class="navigation-wrapper">
          <div class="button-container">
            {/* Mobile logic: only one button at a time, priority to Continue */}
            <div class="osa-toast__back">
              {/* Desktop: always show Back, Mobile: show only if not showing Continue */}
              <button
                type="button"
                aria-label="back"
                class={`back-button${isMobile && capturedAnswer && isClicked && isAnswerRevealed.timeodOutReveal ? ' mobile-hide-when-continue' : ''}`}
                onClick={() => handleProceedQuiz()}
              >
                <span class="bck-arrow">
                  <BackIcon className="bck-arrow__icon" />
                </span>
                <span>Back</span>
              </button>
            </div>
            {/* Continue/Skip button logic for last question */}
            {isLastQuestion ? (
              capturedIndex === -1 ? (
                <button-component label="Skip" onBtnClick={() => handleProceedToNextQuestion(true)}>
                  Skip
                </button-component>
              ) : (
                isClicked && isAnswerRevealed.timeodOutReveal && (
                  <button-component label="Continue" onBtnClick={() => handleProceedToNextQuestion(false)}>
                    Continue
                  </button-component>
                )
              )
            ) : (
              capturedAnswer && isClicked && isAnswerRevealed.timeodOutReveal && (
                <button-component label="Continue" onBtnClick={() => handleProceedToNextQuestion()}>
                  Continue
                </button-component>
              )
            )}
          </div>
        </div>
      </div>
    </div>
  );
};
